import json
from pathlib import Path

OUT = Path(__file__).resolve().parent
TEXTBOOK_META = "Мединский В.Р. и др. История Древнего мира. 5 класс"
TAG_SRC = "Мединский, История Древнего мира, 5 кл."


def base_tags(qt, difficulty_tag, themes, entities=None, concepts=None, processes=None, periods=None, skills=None, geography=None):
    return {
        "entities": entities or [],
        "concepts": concepts or [],
        "processes": processes or [],
        "periods": periods or [],
        "skills": skills or [],
        "geography": geography or [],
        "difficulty": difficulty_tag,
        "question_type": qt,
        "grade": [5],
        "source": TAG_SRC,
        "themes": themes,
    }


def sc(par, pg, nid, q, opts, corr, expl, d1, d2, tags):
    return {
        "id": nid,
        "type": "single_choice",
        "question": q,
        "options": opts,
        "correct_answers": [corr],
        "explanation": expl,
        "source": {"paragraph": par, "page": pg},
        "difficulty": {"primary": d1, "secondary": d2},
        "tags": tags,
    }


def mc(par, pg, nid, q, opts, corr, expl, d1, d2, tags):
    return {
        "id": nid,
        "type": "multiple_choice",
        "question": q,
        "options": opts,
        "correct_answers": corr,
        "explanation": expl,
        "source": {"paragraph": par, "page": pg},
        "difficulty": {"primary": d1, "secondary": d2},
        "tags": tags,
    }


def op(par, pg, nid, q, ca, aa, kw, expl, d1, d2, tags):
    return {
        "id": nid,
        "type": "open",
        "question": q,
        "correct_answer": ca,
        "acceptable_answers": aa,
        "keywords": kw,
        "explanation": expl,
        "source": {"paragraph": par, "page": pg},
        "difficulty": {"primary": d1, "secondary": d2},
        "tags": tags,
    }


def mt(par, pg, nid, q, left, right, pairs, expl, d1, d2, tags):
    return {
        "id": nid,
        "type": "matching",
        "question": q,
        "left_items": left,
        "right_items": right,
        "correct_pairs": pairs,
        "explanation": expl,
        "source": {"paragraph": par, "page": pg},
        "difficulty": {"primary": d1, "secondary": d2},
        "tags": tags,
    }


def ch(par, pg, nid, q, items, order, expl, d1, d2, tags):
    ordered = [items[i] for i in order]
    return {
        "id": nid,
        "type": "chronology",
        "question": q,
        "items": items,
        "correct_order": order,
        "correct_answers": ordered,
        "explanation": expl,
        "source": {"paragraph": par, "page": pg},
        "difficulty": {"primary": d1, "secondary": d2},
        "tags": tags,
    }


