def write(section_num, section_title, questions):
    path = OUT / f"s{section_num}.json"
    data = {"meta": {"textbook": TEXTBOOK_META, "section": section_title}, "questions": questions}
    path.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    print("Wrote", path)


